function.body:
TYPE RECORD IS REF CURSOR;
    Cur_paymentdate  RECORD;
    V_flag NUMBER;
    V_result DATE;
BEGIN 
V_flag:=0;
    FOR Cur_paymentdate IN(

SELECT fp.paymentdate
FROM fin_payment_scheduledetail psd, fin_payment_schedule ps, fin_paymentmethod fpm ,c_invoice i, fin_payment_detail fpd,fin_payment fp
WHERE psd.fin_payment_schedule_invoice = ps.fin_payment_schedule_id 
AND   ps.c_invoice_id = i.c_invoice_id
AND fpd.fin_payment_detail_id = psd.fin_payment_detail_id
AND fpd.fin_payment_id = fp.fin_payment_id
AND fpm.fin_paymentmethod_id = fp.fin_paymentmethod_id
AND i.c_invoice_id= p_cinvoice_id
ORDER BY psd.amount DESC
) LOOP
		V_flag := V_flag +1;
	IF(V_flag =1) THEN
 V_result := Cur_paymentdate.paymentdate ;
	END IF;



END LOOP;

		return V_result;
END SDIN_CANCELLATIONDATE
